const Content = () => {

let PostData=[
  {id: 1, post:"fuck u", likesCount : 5},
  {id: 1, post:"good luck", likesCount : 23},
  {id: 1, post:"nice try", likesCount : 13},
  {id: 1, post:"maybe", likesCount : 76},
  {id: 1, post:"real talk", likesCount : 29}
]

  return (
    <div>
      <div className={s.text}>
        <div> <h2>Content</h2> </div> 
        <Textarea/>
        <Button/>
        <Massages massage = 'fuck u' likesCount = '5'/>
        <Massages massage = 'good luck' likesCount = '65'/>
        <Massages massage = 'nice try' likesCount = '44'/>
        <Massages massage = 'maybe' likesCount = '53'/>
        <Massages massage = 'real talk' likesCount = '12'/>
      </div>
    </div>
  )

}
export default Content;
